#!/usr/bin/env julia
#
# Development-time script that uses Symbolics.jl to auto-generate derivative
# rules for ExaModels' functionlist.jl.
#
# Usage (from repo root):
#   julia --project=deps deps/generate_functionlist.jl          # print to stdout
#   julia --project=deps deps/generate_functionlist.jl --write   # overwrite src/functionlist.jl
#   julia --project=deps deps/generate_functionlist.jl --verify  # verify derivatives only
#
# First-time setup:
#   julia --project=deps -e 'import Pkg; Pkg.instantiate()'
#
# This script is NOT a runtime dependency — it generates static Julia code.

include(joinpath(@__DIR__, "codegen_utils.jl"))

# ============================================================================
# Float64 constants emitted by Symbolics.jl -> type-generic replacements
# ============================================================================

const FLOAT_CONSTANT_REPLACEMENTS = [
    # log constants
    (string(log(2)), "_clog2({V})"),
    (string(log(2)^2), "_clog2({V})^2"),
    (string(log(10)), "_clog10({V})"),
    (string(log(10)^2), "_clog10({V})^2"),
    # π constants
    (string(Float64(π)), "_cpi({V})"),
    (string(Float64(π)^2), "_cpi({V})^2"),
    (string(2 * Float64(π)^2), "(2 * _cpi({V})^2)"),
    (string(Float64(π)^3), "_cpi({V})^3"),
    (string(2 * Float64(π)^3), "(2 * _cpi({V})^3)"),
    (string(Float64(π)^2 * Float64(π)^2), "_cpi({V})^4"), # π²·π² to match Symbolics
    # degree ↔ radian constants
    (string(Float64(π) / 180), "_cd2r({V})"),
    (string(2 * Float64(π) / 180), "(2 * _cd2r({V}))"),
    (string(180 / Float64(π)), "_cr2d({V})"),
]

# ============================================================================
# Function tables
# ============================================================================

# Univariates auto-generated by Symbolics.jl
const AUTO_UNIVARIATES = [
    # Unary operators
    :+, :-,
    # Algebraic
    :inv, :sqrt, :cbrt, :abs, :abs2, :sign,
    # Exponentials / logarithms
    :exp, :exp2, :exp10, :expm1,
    :log, :log2, :log1p, :log10,
    # Trig
    :sin, :cos, :tan, :asin, :acos, :atan, :acot,
    :csc, :sec, :cot,
    # Hyperbolic
    :sinh, :cosh, :tanh, :asinh, :acosh,
    :csch, :sech, :coth,
    # Degree-based trig
    :sind, :cosd, :tand, :cscd, :secd, :cotd, :atand, :acotd,
    # Periodic variants
    :sinpi, :cospi, :sinc,
    # Linear scaling
    :deg2rad, :rad2deg,
    # Piecewise constant (zero derivatives, useful for modeling)
    :signbit, :floor, :ceil,
]

# Univariates needing manual rules (domain guards)
const MANUAL_UNIVARIATES = [
    (:atanh, "x -> abs(x) > one(x) ? oftype(x, NaN) : inv(1 - x^2)", "x -> abs(x) > one(x) ? oftype(x, NaN) : (-abs2(inv(1 - x^2))) * (-2x)"),
    (:acoth, "x -> abs(x) < one(x) ? oftype(x, NaN) : inv(1 - x^2)", "x -> abs(x) < one(x) ? oftype(x, NaN) : (-abs2(inv(1 - x^2))) * (-2x)"),
]

# Bivariates auto-generated by Symbolics.jl
const AUTO_BIVARIATES = [
    :+, :-, :*, :/, :^,
    :atan,   # atan2(y, x)
    :hypot,  # sqrt(x1^2 + x2^2)
    :max, :min,
]

# ============================================================================
# Code generation — outputs src/functionlist.jl
# ============================================================================

function generate()
    io = IOBuffer()

    # --- Helper functions ---
    println(io, "@inline _mone(x) = -one(x)")
    println(io, "@inline _one(x1, x2) = one(x1)")
    println(io, "@inline _zero(x1, x2) = zero(x1)")
    println(io, "@inline _mone(x1, x2) = -one(x1)")
    println(io, "@inline _x1(x1, x2) = x1")
    println(io, "@inline _x2(x1, x2) = x2")
    println(io, "@inline _and(x::Bool, y::Bool) = x && y")
    println(io, "@inline _or(x::Bool, y::Bool) = x || y")
    println(io, "@inline _and(x, y::Bool) = x == 1 && y")
    println(io, "@inline _or(x, y::Bool) = x == 1 || y")
    println(io, "@inline _and(x::Bool, y) = x && y == 1")
    println(io, "@inline _or(x::Bool, y) = x || y == 1")
    println(io, "@inline _and(x, y) = x == 1 && y == 1")
    println(io, "@inline _or(x, y) = x == 1 || y == 1")
    println(io)
    println(io, "# Type-generic constant helpers (avoid Float64 literals for Float32 compatibility)")
    println(io, "@inline _clog2(x) = oftype(x, log(2))")
    println(io, "@inline _clog10(x) = oftype(x, log(10))")
    println(io, "@inline _cpi(x) = oftype(x, π)")
    println(io, "@inline _cd2r(x) = oftype(x, π / 180)")
    println(io, "@inline _cr2d(x) = oftype(x, 180 / π)")
    println(io)

    # --- Registration helpers ---
    println(
        io, raw"""# Runtime registration helpers — use Base.$fname pattern (symbols) to avoid
        # syntax errors with operator function names like Base.:+.

        # _needs_overload: true when no ExaModels-specific method exists yet.
        # Plain `hasmethod` is too conservative — it returns true for
        # untyped Base generics like max(x,y) = ifelse(isless(x,y),y,x),
        # which prevents the Node2 overload from being added.  Check the
        # module of the matched method: only skip if ExaModels already owns it
        # (e.g. the identity-element specializations in specialization.jl).
        function _needs_overload(f, types)
            hasmethod(f, types) || return true
            return which(f, types).module !== @__MODULE__
        end

        function _register_univ(fname::Symbol, df, ddf)
            if _needs_overload(getfield(Base, fname), Tuple{AbstractNode})
                @eval @inline Base.$fname(n::N) where {N <: AbstractNode} = Node1(Base.$fname, n)
            end
            @eval @inline Base.$fname(d::D) where {D <: AbstractAdjointNode} =
                AdjointNode1(Base.$fname, Base.$fname(d.x), ($df)(d.x), d)
            @eval @inline Base.$fname(t::T) where {T <: AbstractSecondAdjointNode} =
                SecondAdjointNode1(Base.$fname, Base.$fname(t.x), ($df)(t.x), ($ddf)(t.x), t)
            return @eval @inline (n::Node1{typeof(Base.$fname), I})(i, x, θ) where {I} =
                Base.$fname(n.inner(i, x, θ))
        end

        function _register_biv(fname::Symbol, df1, df2, ddf11, ddf12, ddf22)
            f = getfield(Base, fname)
            if _needs_overload(f, Tuple{AbstractNode, AbstractNode})
                @eval @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: AbstractNode, D2 <: AbstractNode}
                    return Node2(Base.$fname, d1, d2)
                end
            end
            if _needs_overload(f, Tuple{AbstractNode, Real})
                @eval @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: AbstractNode, D2 <: Real}
                    return Node2(Base.$fname, d1, d2)
                end
            end
            if _needs_overload(f, Tuple{Real, AbstractNode})
                @eval @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: Real, D2 <: AbstractNode}
                    return Node2(Base.$fname, d1, d2)
                end
            end
            return @eval begin
                @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: AbstractAdjointNode, D2 <: AbstractAdjointNode}
                    x1 = d1.x
                    x2 = d2.x
                    return AdjointNode2(Base.$fname, Base.$fname(x1, x2), ($df1)(x1, x2), ($df2)(x1, x2), d1, d2)
                end
                @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: AbstractAdjointNode, D2 <: Union{Real, ParameterNode}}
                    x1 = d1.x
                    x2 = d2
                    return AdjointNode1(Base.$fname, Base.$fname(x1, x2), ($df1)(x1, x2), d1)
                end
                @inline function Base.$fname(
                        d1::D1,
                        d2::D2,
                    ) where {D1 <: Union{Real, ParameterNode}, D2 <: AbstractAdjointNode}
                    x1 = d1
                    x2 = d2.x
                    return AdjointNode1(Base.$fname, Base.$fname(x1, x2), ($df2)(x1, x2), d2)
                end
                @inline function Base.$fname(
                        t1::T1,
                        t2::T2,
                    ) where {T1 <: AbstractSecondAdjointNode, T2 <: AbstractSecondAdjointNode}
                    x1 = t1.x
                    x2 = t2.x
                    return SecondAdjointNode2(
                        Base.$fname,
                        Base.$fname(x1, x2),
                        ($df1)(x1, x2),
                        ($df2)(x1, x2),
                        ($ddf11)(x1, x2),
                        ($ddf12)(x1, x2),
                        ($ddf22)(x1, x2),
                        t1,
                        t2,
                    )
                end
                @inline function Base.$fname(
                        t1::T1,
                        t2::T2,
                    ) where {T1 <: AbstractSecondAdjointNode, T2 <: Union{Real, ParameterNode}}
                    x1 = t1.x
                    x2 = t2
                    return SecondAdjointNode1(
                        SecondFixed(Base.$fname),
                        Base.$fname(x1, x2),
                        ($df1)(x1, x2),
                        ($ddf11)(x1, x2),
                        t1,
                    )
                end
                @inline function Base.$fname(
                        t1::T1,
                        t2::T2,
                    ) where {T1 <: Union{Real, ParameterNode}, T2 <: AbstractSecondAdjointNode}
                    x1 = t1
                    x2 = t2.x
                    return SecondAdjointNode1(
                        FirstFixed(Base.$fname),
                        Base.$fname(x1, x2),
                        ($df2)(x1, x2),
                        ($ddf22)(x1, x2),
                        t2,
                    )
                end
                @inline (n::Node2{typeof(Base.$fname), I1, I2})(i, x, θ) where {I1, I2} =
                    Base.$fname(n.inner1(i, x, θ), n.inner2(i, x, θ))
                @inline (n::Node2{typeof(Base.$fname), I1, I2})(i, x, θ) where {I1 <: Real, I2} =
                    Base.$fname(n.inner1, n.inner2(i, x, θ))
                @inline (n::Node2{typeof(Base.$fname), I1, I2})(i, x, θ) where {I1, I2 <: Real} =
                    Base.$fname(n.inner1(i, x, θ), n.inner2)
            end
        end"""
    )
    println(io)

    # --- Univariate table ---
    println(io, "# " * "="^76)
    println(io, "# Univariate functions: (symbol, df, ddf)")
    println(io, "# Auto-generated by deps/generate_functionlist.jl using Symbolics.jl")
    println(io, "# " * "="^76)
    println(io)
    println(io, "const _UNIVARIATES = [")

    for fname in AUTO_UNIVARIATES
        f_sym = getfield(Base, fname)
        df_sym, ddf_sym = sym_derivs_univ(f_sym)
        df_s = sym2lambda(df_sym, FLOAT_CONSTANT_REPLACEMENTS, :x)
        ddf_s = sym2lambda(ddf_sym, FLOAT_CONSTANT_REPLACEMENTS, :x)
        println(io, "    (:$fname, $df_s, $ddf_s),")
    end

    if !isempty(MANUAL_UNIVARIATES)
        println(io, "    # Manual entries (domain guards)")
        for (fname, df, ddf) in MANUAL_UNIVARIATES
            println(io, "    (:$fname, $df, $ddf),")
        end
    end

    println(io, "]")
    println(io)
    println(io, "for (fname, df, ddf) in _UNIVARIATES")
    println(io, "    _register_univ(fname, df, ddf)")
    println(io, "end")
    println(io)

    # --- Bivariate table ---
    println(io, "# " * "="^76)
    println(io, "# Bivariate functions: (symbol, df1, df2, ddf11, ddf12, ddf22)")
    println(io, "# Auto-generated by deps/generate_functionlist.jl using Symbolics.jl")
    println(io, "# " * "="^76)
    println(io)
    println(io, "const _BIVARIATES = [")

    for fname in AUTO_BIVARIATES
        f_sym = getfield(Base, fname)
        df1_sym, df2_sym, ddf11_sym, ddf12_sym, ddf22_sym = sym_derivs_biv(f_sym)
        df1_s = sym2lambda(df1_sym, FLOAT_CONSTANT_REPLACEMENTS, :x1, :x2)
        df2_s = sym2lambda(df2_sym, FLOAT_CONSTANT_REPLACEMENTS, :x1, :x2)
        ddf11_s = sym2lambda(ddf11_sym, FLOAT_CONSTANT_REPLACEMENTS, :x1, :x2)
        ddf12_s = sym2lambda(ddf12_sym, FLOAT_CONSTANT_REPLACEMENTS, :x1, :x2)
        ddf22_s = sym2lambda(ddf22_sym, FLOAT_CONSTANT_REPLACEMENTS, :x1, :x2)
        println(io, "    (:$fname, $df1_s, $df2_s, $ddf11_s, $ddf12_s, $ddf22_s),")
    end

    println(io, "]")
    println(io)
    println(io, "for (fname, df1, df2, ddf11, ddf12, ddf22) in _BIVARIATES")
    println(io, "    _register_biv(fname, df1, df2, ddf11, ddf12, ddf22)")
    println(io, "end")

    return String(take!(io))
end

# ============================================================================
# Verification: compare Symbolics.jl derivatives against finite differences
# ============================================================================

function verify()
    println("Verifying Symbolics.jl-generated derivatives...")
    h1 = 1.0e-7
    h2 = 1.0e-4
    all_ok = true

    # Test points for domain-sensitive functions
    special_x = Dict(:acosh => 1.7, :sqrt => 0.7, :log => 0.7, :log2 => 0.7, :log10 => 0.7)
    skip_ddf = Set([:signbit, :floor, :ceil, :sign, :abs])  # non-smooth at test point

    for fname in AUTO_UNIVARIATES
        f = getfield(Base, fname)
        df_sym, ddf_sym = sym_derivs_univ(f)
        test_x = get(special_x, fname, 0.7)

        df_fn = Symbolics.build_function(df_sym, x; expression = Val(false))
        ddf_fn = Symbolics.build_function(ddf_sym, x; expression = Val(false))
        df_val = df_fn(test_x)
        ddf_val = ddf_fn(test_x)

        fd_df = (f(test_x + h1) - f(test_x - h1)) / (2h1)
        fd_ddf = (f(test_x + h2) - 2 * f(test_x) + f(test_x - h2)) / h2^2

        if !isapprox(df_val, fd_df; atol = 1.0e-6, rtol = 1.0e-5)
            println("  WARN $fname: df symbolic=$df_val, fd=$fd_df")
            all_ok = false
        end
        if fname ∉ skip_ddf && !isapprox(ddf_val, fd_ddf; atol = 1.0e-6, rtol = 1.0e-4)
            println("  WARN $fname: ddf symbolic=$ddf_val, fd=$fd_ddf")
            all_ok = false
        end
    end

    for fname in AUTO_BIVARIATES
        f = getfield(Base, fname)
        df1_sym, df2_sym, ddf11_sym, ddf12_sym, ddf22_sym = sym_derivs_biv(f)
        tx1, tx2 = 0.7, 1.3
        skip_biv_ddf = fname in (:max, :min)

        for (name, sym) in [("df1", df1_sym), ("df2", df2_sym), ("ddf11", ddf11_sym), ("ddf12", ddf12_sym), ("ddf22", ddf22_sym)]
            fn = Symbolics.build_function(sym, x1, x2; expression = Val(false))
            val = fn(tx1, tx2)

            if startswith(name, "ddf")
                skip_biv_ddf && continue
                if name == "ddf11"
                    fd = (f(tx1 + h2, tx2) - 2 * f(tx1, tx2) + f(tx1 - h2, tx2)) / h2^2
                elseif name == "ddf12"
                    fd = (f(tx1 + h2, tx2 + h2) - f(tx1 + h2, tx2 - h2) - f(tx1 - h2, tx2 + h2) + f(tx1 - h2, tx2 - h2)) / (4 * h2^2)
                else
                    fd = (f(tx1, tx2 + h2) - 2 * f(tx1, tx2) + f(tx1, tx2 - h2)) / h2^2
                end
                if !isapprox(val, fd; atol = 1.0e-6, rtol = 1.0e-4)
                    println("  WARN $fname.$name: symbolic=$val, fd=$fd")
                    all_ok = false
                end
            else
                if name == "df1"
                    fd = (f(tx1 + h1, tx2) - f(tx1 - h1, tx2)) / (2h1)
                else
                    fd = (f(tx1, tx2 + h1) - f(tx1, tx2 - h1)) / (2h1)
                end
                if !isapprox(val, fd; atol = 1.0e-6, rtol = 1.0e-5)
                    println("  WARN $fname.$name: symbolic=$val, fd=$fd")
                    all_ok = false
                end
            end
        end
    end

    n = length(AUTO_UNIVARIATES) + length(AUTO_BIVARIATES)
    return all_ok && println("  All $n auto-generated functions verified OK.")
end

# ============================================================================
# Main
# ============================================================================

function main()
    if "--verify" in ARGS
        verify()
        return
    end

    content = generate()

    if "--write" in ARGS
        outfile = joinpath(dirname(@__DIR__), "src", "functionlist.jl")
        write(outfile, content)
        println("Wrote $(length(content)) bytes to $outfile")
    else
        print(content)
    end

    return verify()
end

if abspath(PROGRAM_FILE) == @__FILE__
    main()
end
